use std::collections::HashMap;

struct Person {
    name: String,
    age: u8,
}

fn main() {
    let people = vec![
        Person { name: "Alice".to_string(), age: 25 },
        Person { name: "Bob".to_string(), age: 30 },
        Person { name: "Alice".to_string(), age: 27 },
    ];

    let multimap: HashMap<String, Vec<u8>> = people.into_iter()
        .map(|p| (p.name, p.age))
        .fold(HashMap::new(), |mut acc, (name, age)| {
            acc.entry(name).or_insert(vec![]).push(age);
            acc
        });

    for (name, ages) in multimap.iter() {
        println!("{}: {:?}", name, ages);
    }
}

